import { useParams } from 'react-router-dom';
import { doc, getDoc, updateDoc, arrayUnion } from 'firebase/firestore';
import { db } from '../services/firebase';
import { useEffect, useState } from 'react';
import BurgerMenu from '../components/BurgerMenu/BurgerMenu';
import { useTranslation } from '../hooks/useTranslation';
import './ActivityDetails.css';

export default function ActivityDetails() {
  const { id } = useParams();
  const [activity, setActivity] = useState<any>(null);
  const t = useTranslation();

  useEffect(() => {
    const fetchActivity = async () => {
      if (!id) return;
      const docRef = doc(db, 'activities', id);
      const docSnap = await getDoc(docRef);
      if (docSnap.exists()) {
        setActivity({ id: docSnap.id, ...docSnap.data() });
      }
    };
    fetchActivity();
  }, [id]);

  const handleJoin = async () => {
    if (!id) return;
    // В реальном приложении здесь нужно использовать ID текущего пользователя
    const userId = "temp-user-id"; 
    await updateDoc(doc(db, 'activities', id), {
      people: arrayUnion(userId)
    });
    setActivity({
      ...activity,
      people: [...activity.people, userId]
    });
  };

  if (!activity) return <div>Loading...</div>;

  return (
    <div className="activity-details-page">
      <BurgerMenu />
      <div className="content">
        <h1>{activity.title}</h1>
        <div className="details-card">
          <p><strong>{t.location}:</strong> {activity.location}</p>
          <p><strong>{t.date}:</strong> {new Date(activity.date).toLocaleString()}</p>
          <p><strong>{t.description}:</strong> {activity.description}</p>
          <p><strong>Участники:</strong> {activity.people?.length || 0}</p>
          <button onClick={handleJoin} className="join-btn">
            {t.join}
          </button>
        </div>
      </div>
    </div>
  );
}
